let func = function (body, data) {
    //---校验列表
    if (!body.snList || !Array.isArray(body.snList) || body.snList.length < 1) {
        return { "err": "error", "msg": "snList error", "data": body.snList };
    }
    let snObj = {};
    for (let i = 0; i < body.snList.length; i++) {
        let sn = body.snList[i].replace(/\r\n/g, "").replace(/\n/g, "").replace(/\r/g, "");
