            return { "err": "error", "msg": "sn error" };
        }
        if (!snObj[sn]) {
            snObj[sn] = true;
            data.snList = data.snList ? `${data.snList},'${sn}'` : `'${sn}'`; // 优化字符串拼接
        }
    }
}
let data = {snList:""}
let err = func($input.all()[0].json.body, data);
return err ? err : { "err": "ok", "snList": data.snList };

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
let error = "";
const SELECT_SQL = [];
const SELECT_SQL_SN = [];
const SELECT_SAP = [];
const snList = $('请求入口').all()[0].json.body.snList;
const snList_new = [];
const snObject = {};
const woSAPObject = {};
const woSQLObject = {};

// 临时用，因为非标准工单存在和正式工单一样的格式
const tmp = {};
let snprod = $('提取snList').all()[0].json.woList;

try {
  if($('根据SN查询工单数据（旧MES）')) {
    for (const item of $input.all()) {
      tmp[item.json.sn] = item.json.m;
    }
  }
} catch (error) {}

// 统一处理逻辑
if(!snprod || !snprod.length || (snprod.length==1 && !snprod[0].json.uuid)) {
  for (const sn of snList) {
    SELECT_SQL_SN.push('\''+sn+'\'');
  }
}

for (const item of snprod) {
  if(!item.json.uuid) continue;

  if(isNaN(item.json.jobnumber2) || tmp[item.json.uuid]) {
    SELECT_SQL_SN.push('\''+item.json.uuid+'\'');
  } else {
    snList_new.push(item.json.uuid);
    const isnew = item.json.createtime2 && new Date(item.json.createtime2) > new Date('2023-10-01 00:00:00');

    if(item.json.jobnumber2 && item.json.uuid) {
      snObject[item.json.uuid] = item.json.jobnumber2;
      const targetObj = isnew ? woSAPObject : woSQLObject;

      if(targetObj[item.json.jobnumber2]) {
        targetObj[item.json.jobnumber2].push(item.json.uuid);
      } else {
        targetObj[item.json.jobnumber2] = [item.json.uuid];
      }
    }

    if(item.json.jobnumber2) {
      isnew ? 
        SELECT_SAP.push({"AUFNR": item.json.jobnumber2}) : 
        SELECT_SQL.push('\''+item.json.jobnumber2+'\'');
    }
  }
}

// 错误处理
for(let i=0;i<snList_new.length;i++){
  const sn = snList_new[i].replace(/\r\n/g, "").replace(/\n/g, "").replace(/\r/g, "");
  if(!snObject[sn]){
    error = error ? `${error},${sn}` : sn;
  }
}

return {
  "error" : error,
  "woSAPObject": woSAPObject,
  "woSQLObject": woSQLObject,
  "SELECT_SQL": SELECT_SQL,
  "IS_SELECT_SAP": SELECT_SAP.length>0,
  "SELECT_SAP": JSON.stringify(SELECT_SAP),
  "SELECT_SQL_SN": SELECT_SQL_SN
};

