reqList.forEach(sn => {
  if (!sn || processedSNs.has(sn)) return;
  processedSNs.add(sn);

  const inputItem = inputData.find(item => item.json.sn === sn);

  if (!inputItem || shouldExcludeFromSnList(inputItem)) {
    snNoFindList.push(sn);
  } else {
    snList.push(inputItem.json);
  }
});

const res = [];

